import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";

const orderedSources = [
  "scripts/modules/content-data.js",
  "scripts/modules/render-content.js",
  "scripts/modules/scroll-progress.js",
  "scripts/modules/clock.js",
  "scripts/modules/cursor.js",
  "scripts/modules/toggle.js",
  "scripts/modules/menu-panels.js",
  "scripts/modules/parallax.js",
  "scripts/main.js"
];

const outputPath = resolve("scripts/site.js");

function stripImports(source) {
  const lines = source.split("\n");
  const kept = [];
  let inImport = false;

  for (const line of lines) {
    const trimmed = line.trim();
    if (!inImport && trimmed.startsWith("import ")) {
      if (!trimmed.includes(" from ")) inImport = true;
      continue;
    }

    if (inImport) {
      if (trimmed.includes(" from ")) inImport = false;
      continue;
    }

    kept.push(line);
  }

  return kept.join("\n");
}

function toClassicScript(path) {
  const source = readFileSync(path, "utf8");
  return stripImports(source)
    .replace(/^export\s+(const|let|var|function|class)\s+/gm, "$1 ")
    .trim();
}

const body = orderedSources
  .map((path) => `  // ${path}\n${toClassicScript(path)}`)
  .join("\n\n")
  .replace(/^/gm, "  ");

const bundle = `// Generated by tools/build-classic-bundle.mjs from scripts/main.js and scripts/modules/*.js.
// Do not edit by hand; edit the source modules and run npm run build:scripts.
(function () {
  "use strict";

${body}
}());
`;

mkdirSync(dirname(outputPath), { recursive: true });
writeFileSync(outputPath, bundle, "utf8");
console.log(`built ${outputPath}`);
